const FIXTURES_DIR = path.resolve(__dirname, '../../harnesses/fixtures');

interface ScriptServiceFixture {
  readonly language: string;
  readonly fileName: string;
  readonly sourceText: string;
  readonly expectedBody: string;
  readonly isAvailable: () => boolean;
  readonly timeoutMs?: number;
}

function isCommandAvailable(command: string): boolean {
  try {
    execFileSync('sh', ['-lc', `command -v ${command}`], {
      stdio: 'ignore',
    });
    return true;
  } catch {
    return false;
  }
}

function decodeCompatibilityBody(responseValue: unknown): string | null {
  const body = (responseValue as { response?: { body?: { value?: string } } })
    ?.response?.body;

  if (!body?.value) {
    return null;
  }

  return Buffer.from(body.value, 'base64').toString('utf8');
}

function removeIfPresent(filePath: string): void {
  try {
    fs.unlinkSync(filePath);
  } catch (error) {
    const errno = error as NodeJS.ErrnoException;
    if (errno.code !== 'ENOENT') {
      throw error;
    }
  }
}

async function withSubprocessTimeout<T>(
  timeoutMs: number,
  fn: () => Promise<T>
): Promise<T> {
  const previousTimeout = process.env.GNODE_SUBPROCESS_TIMEOUT_MS;
  process.env.GNODE_SUBPROCESS_TIMEOUT_MS = String(timeoutMs);

  try {
    return await fn();
  } finally {
    if (previousTimeout === undefined) {
      delete process.env.GNODE_SUBPROCESS_TIMEOUT_MS;
    } else {
      process.env.GNODE_SUBPROCESS_TIMEOUT_MS = previousTimeout;
    }
  }
}

function normalizeFixtureSource(sourceText: string): string {
  const trimmed = sourceText.replace(/^\s*\n/, '').replace(/\s+$/, '');
  const lines = trimmed.split('\n');
  const indentation = lines
    .filter((line) => line.trim().length > 0)
    .reduce((minimumIndentation, line) => {
      const nextIndentation = line.match(/^\s*/)?.[0].length ?? 0;
      return Math.min(minimumIndentation, nextIndentation);
    }, Number.POSITIVE_INFINITY);

  const normalizedLines = lines.map((line) =>
    Number.isFinite(indentation) ? line.slice(indentation) : line
  );

  return `${normalizedLines.join('\n')}\n`;
}

let scriptServiceFixtureRunId = 0;

function makeScriptServiceTempFilePath(fixture: ScriptServiceFixture): string {
  scriptServiceFixtureRunId += 1;

  const safeLanguage = fixture.language.replace(/[^a-z0-9_-]+/gi, '-');
  const uniqueSuffix = `${process.pid}-${Date.now()}-${scriptServiceFixtureRunId}`;

  return path.join(
    FIXTURES_DIR,
    `script-service-${safeLanguage}-${uniqueSuffix}-${fixture.fileName}`
  );
}

