// ─── Cross-Language Trace Tests ──────────────────────────────────────────────

describe('cross-language execution trace', () => {
  test('builds backward trace from failed node', () => {
    const nodes = new Map<string, ASTNode>();
    nodes.set('entry', {
      id: 'entry',
      labels: ['Entry', 'PolyglotBridgeEntry'],
      properties: { name: 'pipeline', language: 'javascript' },
    });
    nodes.set('parse', {
      id: 'parse',
      labels: ['Statement', 'PolyglotBridgeCall'],
      properties: { language: 'rust', callee: 'parse_input' },
    });
    nodes.set('fetch', {
      id: 'fetch',
      labels: ['Statement', 'PolyglotBridgeCall'],
      properties: { language: 'go', callee: 'fetch_data' },
    });
    nodes.set('predict', {
      id: 'predict',
      labels: ['Statement', 'PolyglotBridgeCall'],
      properties: { language: 'python', callee: 'ml_predict' },
    });

    const edges: ASTEdge[] = [
      {
        sourceIds: ['entry'],
        targetIds: ['parse'],
        type: 'PROCESS',
        properties: {},
      },
      {
        sourceIds: ['parse'],
        targetIds: ['fetch'],
        type: 'PROCESS',
        properties: {},
      },
      {
        sourceIds: ['fetch'],
        targetIds: ['predict'],
        type: 'PROCESS',
        properties: {},
      },
    ];

    const ast: GraphAST = { nodes, edges };
    const manifest: PolyglotExecutionManifest = {
      language: 'javascript',
      file_path: '/pipeline',
      entry_function: 'pipeline',
      node_execution_plans: [
        {
          node_id: 'entry',
          source_range: { start_byte: 0, end_byte: 10 },
          kind: 'entry',
        },
        {
          node_id: 'parse',
          source_range: { start_byte: 10, end_byte: 50 },
          kind: 'call',
          callee: 'parse_input',
        },
        {
          node_id: 'fetch',
          source_range: { start_byte: 50, end_byte: 90 },
          kind: 'call',
          callee: 'fetch_data',
        },
        {
          node_id: 'predict',
          source_range: { start_byte: 90, end_byte: 130 },
          kind: 'call',
          callee: 'ml_predict',
        },
      ],
    };

    const mappedError = {
      language: 'python',
      filePath: 'ml.py',
      functionName: 'ml_predict',
      message: 'ValueError: could not convert string to float',
      line: 42,
      traceback: 'Traceback...',
    };

    const trace = buildExecutionTrace(ast, 'predict', mappedError, manifest);

    expect(trace.frames.length).toBe(4);
    expect(trace.failedNode).toBe('predict');
    expect(trace.analysis.languages).toContain('python');
    expect(trace.analysis.languages).toContain('go');
    expect(trace.analysis.languages).toContain('rust');
    expect(trace.analysis.errorKind).toBe('semantic');
    expect(trace.frames[3]!.status).toBe('error');
    expect(trace.frames[3]!.line).toBe(42);
  });

  test('formatExecutionTrace produces readable output', () => {
    const trace = {
      frames: [
        {
          nodeId: 'entry',
          labels: ['Entry'],
          language: 'javascript',
          filePath: '/p',
          functionName: 'pipeline',
          status: 'completed' as const,
          incomingEdgeType: undefined,
        },
        {
          nodeId: 'predict',
          labels: ['Statement'],
          language: 'python',
          filePath: 'ml.py',
          functionName: 'ml_predict',
          status: 'error' as const,
          line: 42,
          incomingEdgeType: 'PROCESS',
        },
      ],
      failedNode: 'predict',
      mappedError: {
        language: 'python',
        filePath: 'ml.py',
        functionName: 'ml_predict',
        message: 'ValueError',
        line: 42,
        traceback: '',
      },
      analysis: {
        pathLength: 2,
        languages: ['javascript', 'python'],
        errorKind: 'semantic' as const,
        edgeTypes: ['PROCESS'],
      },
    };

    const formatted = formatExecutionTrace(trace);
    expect(formatted).toContain('predict');
    expect(formatted).toContain('python');
    expect(formatted).toContain('42');
    expect(formatted).toContain('semantic');
  });
});

